+			"Stop": [{"matcher": "", "hooks": [{"type": "command", "command": "gt handoff"}]}]
+		}
+	}`
+	if err := os.WriteFile(staleTownRootSettings, []byte(settingsContent), 0644); err != nil {
+		t.Fatal(err)
+	}
+
+	check := NewClaudeSettingsCheck()
+	ctx := &CheckContext{TownRoot: tmpDir}
